const solve = (points, target) => {
    // Helper function to convert a point array [x, y, z] to a unique string key
    const pointToKey = (p) => `${p[0]},${p[1]},${p[2]}`;

    // Helper function to convert a key string back to an array
    const keyToPoint = (key) => key.split(',').map(Number);

    // 1. Initialize the set of all known points (P)
    let allPointsSet = new Set();
    const initialPoints = points.map(p => pointToKey(p));
    for (const key of initialPoints) {
        allPointsSet.add(key);
    }

    const targetKey = pointToKey(target);

    // Check Generation 0
    if (allPointsSet.has(targetKey)) {
        return 0;
    }

    let k = 0;
    let pointsArray = points; // Start with the initial array representation for easy indexing

    // We iterate indefinitely until we find the target or determine stabilization/unreachability.
    while (true) {
        k++;
        let newlyGeneratedKeys = new Set();
        let generatedAnyNewPoints = false;

        // Get the current list of points from the set (O(N) conversion)
        let currentPointsKeys = Array.from(allPointsSet);
        const N = currentPointsKeys.length;

        // If we have fewer than 2 distinct points, we cannot generate any new points.
        if (N < 2) {
            return -1;
        }

        // 2. Generate all midpoints (N_k) from pairs of distinct points in P
        for (let i = 0; i < N; i++) {
            for (let j = i + 1; j < N; j++) {
                const keyA = currentPointsKeys[i];
                const keyB = currentPointsKeys[j];

                const A = keyToPoint(keyA);
                const B = keyToPoint(keyB);

                // Calculate midpoint c = [floor((x1 + x2) / 2), ...]
                const c = [
                    Math.floor((A[0] + B[0]) / 2),
                    Math.floor((A[1] + B[1]) / 2),
                    Math.floor((A[2] + B[2]) / 2)
                ];

                const cKey = pointToKey(c);

                // Check if this new point is the target
                if (cKey === targetKey) {
                    return k;
                }

                // If the point is genuinely new, we track it
                if (!allPointsSet.has(cKey)) {
                    newlyGeneratedKeys.add(cKey);
                    generatedAnyNewPoints = true;
                }
            }
        }

        // 3. Update the set P for the next generation
        if (!generatedAnyNewPoints) {
            // If no new unique points were generated, the set has stabilized, and the target was not found.
            return -1;
        }

        for (const newKey of newlyGeneratedKeys) {
            allPointsSet.add(newKey);
        }

        // Safety break: Although coordinate limits (0-6) imply finite search space (343 points), 
        // this loop structure is guaranteed to terminate due to stabilization or finding the target.
    }
};

